    #[test]
    fn fingerprint_collection_skips_cache_dirs() {
        let tmp = tempdir().unwrap();
        fs::create_dir_all(tmp.path().join("node_modules/pkg")).unwrap();
        fs::write(tmp.path().join("node_modules/pkg/package.json"), "{}").unwrap();
        fs::write(tmp.path().join("package.json"), "{}").unwrap();

        let fingerprint = fingerprint_root(tmp.path()).unwrap().unwrap();
        assert_eq!(fingerprint.files, vec!["package.json"]);
    }

    #[test]
    fn scoped_fingerprint_ignores_unrelated_package_roots() {
        let source = tempdir().unwrap();
        let target = tempdir().unwrap();

        fs::create_dir_all(source.path().join("apps/studio/node_modules")).unwrap();
        fs::create_dir_all(source.path().join("engine/node_modules")).unwrap();
        fs::create_dir_all(
            source
                .path()
                .join("apps/studio/native/modules/mesh-napi/target"),
        )
        .unwrap();

        fs::create_dir_all(target.path().join("apps/studio/node_modules")).unwrap();
        fs::create_dir_all(target.path().join("engine/node_modules")).unwrap();
        fs::create_dir_all(
            target
                .path()
                .join("apps/studio/native/modules/mesh-napi/target"),
        )
        .unwrap();
        fs::create_dir_all(target.path().join("apps/other-tool")).unwrap();

        for root in [source.path(), target.path()] {
            fs::write(
                root.join("apps/studio/package.json"),
                "{\"name\":\"studio\"}",
            )
            .unwrap();
            fs::write(root.join("apps/studio/package-lock.json"), "{}").unwrap();
            fs::write(root.join("engine/package.json"), "{\"name\":\"engine\"}").unwrap();
            fs::write(root.join("engine/package-lock.json"), "{}").unwrap();
            fs::write(
                root.join("apps/studio/native/modules/mesh-napi/Cargo.lock"),
                "mesh-lock",
            )
            .unwrap();
            fs::write(
                root.join("apps/studio/native/modules/mesh-napi/package.json"),
                "{\"name\":\"mesh-napi\"}",
            )
            .unwrap();
        }

        fs::write(
            target.path().join("apps/other-tool/package.json"),
            "{\"name\":\"other-tool\"}",
        )
        .unwrap();

        let rel_paths = hydration_paths(source.path(), Some(CacheProfile::Designer), &[]).unwrap();
        let verification =
            verify_fingerprints(source.path(), target.path(), &rel_paths, false).unwrap();

        assert!(verification.approved);
        let source_files = verification
            .source
            .as_ref()
            .map(|snapshot| snapshot.files.clone())
            .unwrap();
        assert!(source_files.contains(&"apps/studio/package.json".to_string()));
        assert!(source_files.contains(&"engine/package.json".to_string()));
        assert!(!source_files.contains(&"apps/other-tool/package.json".to_string()));
    }

    #[test]
    fn scoped_fingerprint_understands_dotnet_roots() {
        let source = tempdir().unwrap();
        let target = tempdir().unwrap();

        for root in [source.path(), target.path()] {
            fs::create_dir_all(root.join("cascode/build/native/darwin-arm64")).unwrap();
            fs::create_dir_all(root.join("cascode/editors/node/build/Release")).unwrap();
            fs::create_dir_all(root.join("cascode/tools/native/Cascode.Native")).unwrap();
            fs::write(root.join("cascode/Cascode.sln"), "Project").unwrap();
            fs::write(
                root.join("cascode/tools/native/Cascode.Native/Cascode.Native.csproj"),
                "<Project />",
            )
            .unwrap();
            fs::write(
                root.join("cascode/editors/node/package.json"),
                "{\"name\":\"cascode-node\"}",
            )
            .unwrap();
            fs::write(root.join("cascode/editors/node/package-lock.json"), "{}").unwrap();
        }

        fs::create_dir_all(source.path().join("x/nikiv/build123d-lsp")).unwrap();
        fs::create_dir_all(target.path().join("x/nikiv/build123d-lsp")).unwrap();
        fs::write(
            source.path().join("x/nikiv/build123d-lsp/Cargo.lock"),
            "source-lock",
        )
        .unwrap();
        fs::write(
            target.path().join("x/nikiv/build123d-lsp/Cargo.lock"),
            "target-lock",
        )
        .unwrap();

        let rel_paths = vec![
            PathBuf::from("cascode/build/native/darwin-arm64"),
            PathBuf::from("cascode/editors/node/build/Release"),
        ];
        let verification =
            verify_fingerprints(source.path(), target.path(), &rel_paths, false).unwrap();

        assert!(verification.approved);
        let source_files = verification
            .source
            .as_ref()
            .map(|snapshot| snapshot.files.clone())
            .unwrap();
        assert!(source_files.contains(&"cascode/Cascode.sln".to_string()));
        assert!(
            source_files
                .contains(&"cascode/tools/native/Cascode.Native/Cascode.Native.csproj".to_string())
        );
        assert!(source_files.contains(&"cascode/editors/node/package.json".to_string()));
        assert!(!source_files.contains(&"x/nikiv/build123d-lsp/Cargo.lock".to_string()));
    }

    #[test]
    fn scoped_fingerprint_ignores_generated_dotnet_obj_metadata() {
        let source = tempdir().unwrap();
        let target = tempdir().unwrap();

        for root in [source.path(), target.path()] {
            fs::create_dir_all(root.join("cascode/build/native/darwin-arm64")).unwrap();
            fs::create_dir_all(root.join("cascode/editors/node/build/Release")).unwrap();
            fs::create_dir_all(root.join("cascode/tools/native/Cascode.Native/obj")).unwrap();
            fs::write(root.join("cascode/Cascode.sln"), "Project").unwrap();
            fs::write(root.join("cascode/Directory.Build.props"), "<Project />").unwrap();
            fs::write(
                root.join("cascode/tools/native/Cascode.Native/Cascode.Native.csproj"),
                "<Project />",
            )
            .unwrap();
            fs::write(
                root.join("cascode/editors/node/package.json"),
                "{\"name\":\"cascode-node\"}",
            )
            .unwrap();
            fs::write(root.join("cascode/editors/node/package-lock.json"), "{}").unwrap();
        }

        fs::write(
            source.path().join(
                "cascode/tools/native/Cascode.Native/obj/Cascode.Native.csproj.nuget.g.props",
            ),
            "source-generated",
        )
        .unwrap();
        fs::write(
            target.path().join(
                "cascode/tools/native/Cascode.Native/obj/Cascode.Native.csproj.nuget.g.props",
            ),
            "target-generated",
        )
        .unwrap();

        let rel_paths = vec![
            PathBuf::from("cascode/build/native/darwin-arm64"),
            PathBuf::from("cascode/editors/node/build/Release"),
        ];
        let verification =
            verify_fingerprints(source.path(), target.path(), &rel_paths, false).unwrap();

        assert!(verification.approved);
        let source_files = verification
            .source
            .as_ref()
            .map(|snapshot| snapshot.files.clone())
            .unwrap();
        assert!(source_files.contains(&"cascode/Cascode.sln".to_string()));
        assert!(source_files.contains(&"cascode/Directory.Build.props".to_string()));
        assert!(!source_files.iter().any(|path| path.contains("/obj/")));
    }

    #[test]
    fn allow_unverified_approves_mismatched_fingerprints() {
        let source = tempdir().unwrap();
        let target = tempdir().unwrap();

        for root in [source.path(), target.path()] {
            fs::create_dir_all(root.join("ide/x/wguss/ocpbind/work/build/upstream-ocp-compile"))
                .unwrap();
            fs::write(
                root.join("ide/x/wguss/ocpbind/package.json"),
                "{\"name\":\"ocpbind\"}",
            )
            .unwrap();
            fs::write(root.join("ide/x/wguss/ocpbind/package-lock.json"), "{}").unwrap();
            fs::write(
                root.join("ide/x/wguss/ocpbind/pyproject.toml"),
                "[project]\nname='ocpbind'\n",
            )
            .unwrap();
            fs::write(root.join("ide/x/wguss/ocpbind/uv.lock"), "lock").unwrap();
        }

        fs::write(
            source.path().join("ide/x/wguss/ocpbind/package-lock.json"),
            "{\"version\":\"source\"}",
        )
        .unwrap();
        fs::write(
            target.path().join("ide/x/wguss/ocpbind/package-lock.json"),
            "{\"version\":\"target\"}",
        )
        .unwrap();

        let rel_paths = vec![PathBuf::from(
            "ide/x/wguss/ocpbind/work/build/upstream-ocp-compile",
        )];
        let verification =
            verify_fingerprints(source.path(), target.path(), &rel_paths, true).unwrap();

        assert!(verification.approved);
        assert!(matches!(
            verification.status,
            VerificationStatus::Unverified
        ));
        assert_eq!(
            verification.reason.as_deref(),
            Some("dependency fingerprints differ; proceeding because --allow-unverified was set")
        );
    }

    fn test_workspace_spec(workspace_path: PathBuf) -> WorkspaceSpec {
        WorkspaceSpec {
            repo_root: workspace_path.clone(),
            focus_path: PathBuf::from("ide/designer"),
            workspace_name: "review-feature".to_string(),
            workspace_path,
            revision: None,
            jj_bin: PathBuf::from("jj"),
        }
    }

    #[test]
    fn ensure_generated_workspace_flow_toml_writes_designer_wrapper() {
        let tmp = tempdir().unwrap();
        fs::create_dir_all(tmp.path().join("ide/designer")).unwrap();
        fs::write(
            tmp.path().join("ide/designer/flow.toml"),
            "version = 1\nname = \"designer\"\n",
        )
        .unwrap();

        ensure_generated_workspace_flow_toml(&test_workspace_spec(tmp.path().to_path_buf()))
            .unwrap();

        let generated = fs::read_to_string(tmp.path().join("flow.toml")).unwrap();
        assert!(generated.starts_with(GENERATED_WORKSPACE_FLOW_HEADER));
        assert!(generated.contains("name = \"hot\""));
        assert!(generated.contains("name = \"runtime\""));
        assert!(generated.contains("\"hot-clean\" = \"root\""));
    }

    #[test]
    fn ensure_generated_workspace_flow_toml_preserves_manual_root_config() {
        let tmp = tempdir().unwrap();
        fs::create_dir_all(tmp.path().join("ide/designer")).unwrap();
        fs::write(
            tmp.path().join("ide/designer/flow.toml"),
            "version = 1\nname = \"designer\"\n",
        )
        .unwrap();
        fs::write(
            tmp.path().join("flow.toml"),
            "version = 1\n[[tasks]]\nname = \"custom\"\ncommand = \"echo custom\"\n",
        )
        .unwrap();

        ensure_generated_workspace_flow_toml(&test_workspace_spec(tmp.path().to_path_buf()))
            .unwrap();

        let generated = fs::read_to_string(tmp.path().join("flow.toml")).unwrap();
        assert!(generated.contains("name = \"custom\""));
        assert!(!generated.starts_with(GENERATED_WORKSPACE_FLOW_HEADER));
    }

    #[test]
    fn repair_zero_byte_mismatches_restores_truncated_node_modules_files() {
        let source = tempdir().unwrap();
        let target = tempdir().unwrap();

        let rel = PathBuf::from("ide/designer/node_modules/tunnel-rat/tsconfig.json");
        let source_file = source.path().join(&rel);
        let target_file = target.path().join(&rel);

        fs::create_dir_all(source_file.parent().unwrap()).unwrap();
        fs::create_dir_all(target_file.parent().unwrap()).unwrap();
        fs::write(
            &source_file,
            "{\n  \"compilerOptions\": {\"baseUrl\": \".\"}\n}\n",
        )
        .unwrap();
        fs::write(&target_file, "").unwrap();

        let repaired = repair_zero_byte_mismatches(
            &source.path().join("ide/designer/node_modules"),
            &target.path().join("ide/designer/node_modules"),
        )
        .unwrap();

        assert_eq!(repaired, 1);
        assert_eq!(
            fs::read_to_string(&target_file).unwrap(),
            fs::read_to_string(&source_file).unwrap()
        );
    }

